// ============================================================================
// Helper: upload data, run GPU KDE, compare against golden expected values
// ============================================================================

template <typename T>
void run_kde_golden(const double* query_data,
                    const double* train_data,
                    int n_query,
                    int n_train,
                    int d,
                    const double* weights_data,
                    T bandwidth,
                    DensityKernelType kernel,
                    DistanceType metric,
                    T metric_arg,
                    const double* expected,
                    T tolerance)
{
  // Convert input data to test precision
  std::vector<T> h_query(n_query * d);
  std::vector<T> h_train(n_train * d);
  for (int i = 0; i < n_query * d; ++i)
    h_query[i] = static_cast<T>(query_data[i]);
  for (int i = 0; i < n_train * d; ++i)
    h_train[i] = static_cast<T>(train_data[i]);

  std::vector<T> h_weights;
  T sum_weights = static_cast<T>(n_train);
  if (weights_data) {
    h_weights.resize(n_train);
    sum_weights = T(0);
    for (int i = 0; i < n_train; ++i) {
      h_weights[i] = static_cast<T>(weights_data[i]);
      sum_weights += h_weights[i];
    }
  }

  std::vector<T> h_expected(n_query);
  for (int i = 0; i < n_query; ++i)
    h_expected[i] = static_cast<T>(expected[i]);

  // Device allocations
  raft::resources handle;
  auto stream = raft::resource::get_cuda_stream(handle);

  rmm::device_uvector<T> d_query(n_query * d, stream);
  rmm::device_uvector<T> d_train(n_train * d, stream);
  rmm::device_uvector<T> d_output(n_query, stream);
  rmm::device_uvector<T> d_weights(weights_data ? n_train : 0, stream);

  raft::update_device(d_query.data(), h_query.data(), n_query * d, stream);
  raft::update_device(d_train.data(), h_train.data(), n_train * d, stream);
  if (weights_data) { raft::update_device(d_weights.data(), h_weights.data(), n_train, stream); }

  auto query_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_query.data(), static_cast<std::int64_t>(n_query), static_cast<std::int64_t>(d));
  auto train_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_train.data(), static_cast<std::int64_t>(n_train), static_cast<std::int64_t>(d));
  auto output_view = raft::make_device_vector_view<T, std::int64_t>(
    d_output.data(), static_cast<std::int64_t>(n_query));

  std::optional<raft::device_vector_view<const T, std::int64_t>> weights_opt;
  if (weights_data) {
    weights_opt = raft::make_device_vector_view<const T, std::int64_t>(
      d_weights.data(), static_cast<std::int64_t>(n_train));
  }

  cuvs::distance::kde<T>(handle,
                         query_view,
                         train_view,
                         weights_opt,
                         output_view,
                         bandwidth,
                         sum_weights,
                         kernel,
                         metric,
                         metric_arg);

  ASSERT_TRUE(cuvs::devArrMatchHost(
    h_expected.data(), d_output.data(), n_query, cuvs::CompareApprox<T>(tolerance), stream));
}

// ============================================================================
// Multi-pass helper: deterministic data generation matching the Python script
// ============================================================================

template <typename T>
void run_kde_multipass(const double* expected, bool weighted, T tolerance)
{
  constexpr int nq = 2, nt = 2000, dim = 3;
  std::vector<T> h_query(nq * dim);
  std::vector<T> h_train(nt * dim);
  for (int i = 0; i < nq; ++i)
    for (int j = 0; j < dim; ++j)
      h_query[i * dim + j] = T(0.1) + T(((i * 1337 + j * 7 + 42) % 1000) / 1000.0 * 1.9);
  for (int i = 0; i < nt; ++i)
    for (int j = 0; j < dim; ++j)
      h_train[i * dim + j] = T(0.1) + T(((i * 1337 + j * 7 + 42) % 1000) / 1000.0 * 1.9);

  std::vector<T> h_weights(nt);
  T sum_weights = static_cast<T>(nt);
  if (weighted) {
    sum_weights = T(0);
    for (int i = 0; i < nt; ++i) {
      h_weights[i] = T(0.5) + T(((i * 31 + 17) % 1000) / 1000.0 * 2.5);
      sum_weights += h_weights[i];
    }
  }

  std::vector<T> h_expected(nq);
  for (int i = 0; i < nq; ++i)
    h_expected[i] = static_cast<T>(expected[i]);

  raft::resources handle;
  auto stream = raft::resource::get_cuda_stream(handle);

  rmm::device_uvector<T> d_query(nq * dim, stream);
  rmm::device_uvector<T> d_train(nt * dim, stream);
  rmm::device_uvector<T> d_output(nq, stream);
  rmm::device_uvector<T> d_weights(weighted ? nt : 0, stream);

  raft::update_device(d_query.data(), h_query.data(), nq * dim, stream);
  raft::update_device(d_train.data(), h_train.data(), nt * dim, stream);
  if (weighted) { raft::update_device(d_weights.data(), h_weights.data(), nt, stream); }

  auto query_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_query.data(), std::int64_t(nq), std::int64_t(dim));
  auto train_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_train.data(), std::int64_t(nt), std::int64_t(dim));
  auto output_view =
    raft::make_device_vector_view<T, std::int64_t>(d_output.data(), std::int64_t(nq));

  std::optional<raft::device_vector_view<const T, std::int64_t>> weights_opt;
  if (weighted) {
    weights_opt =
      raft::make_device_vector_view<const T, std::int64_t>(d_weights.data(), std::int64_t(nt));
  }

  cuvs::distance::kde<T>(handle,
                         query_view,
                         train_view,
                         weights_opt,
                         output_view,
                         T(1.0),
                         sum_weights,
                         DensityKernelType::Gaussian,
                         DistanceType::L2SqrtUnexpanded,
                         T(2.0));

  ASSERT_TRUE(cuvs::devArrMatchHost(
    h_expected.data(), d_output.data(), nq, cuvs::CompareApprox<T>(tolerance), stream));
}

// ============================================================================
// High-dimensional helper: exercises feature tiling (d > feat_tile=64)
// and train tiling (n_train > CELL_TILE).
// ============================================================================

template <typename T>
void run_kde_highd(int nt, int dim, const double* expected, T tolerance)
{
  constexpr int nq = 4;
  std::vector<T> h_query(nq * dim);
  std::vector<T> h_train(nt * dim);
  for (int i = 0; i < nq; ++i)
    for (int j = 0; j < dim; ++j)
      h_query[i * dim + j] = T(0.1) + T(((i * 1337 + j * 7 + 42) % 1000) / 1000.0 * 1.9);
  for (int i = 0; i < nt; ++i)
    for (int j = 0; j < dim; ++j)
      h_train[i * dim + j] = T(0.1) + T(((i * 1337 + j * 7 + 42) % 1000) / 1000.0 * 1.9);

  std::vector<T> h_expected(nq);
  for (int i = 0; i < nq; ++i)
    h_expected[i] = static_cast<T>(expected[i]);

  raft::resources handle;
  auto stream = raft::resource::get_cuda_stream(handle);

  rmm::device_uvector<T> d_query(nq * dim, stream);
  rmm::device_uvector<T> d_train(nt * dim, stream);
  rmm::device_uvector<T> d_output(nq, stream);

  raft::update_device(d_query.data(), h_query.data(), nq * dim, stream);
  raft::update_device(d_train.data(), h_train.data(), nt * dim, stream);

  auto query_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_query.data(), std::int64_t(nq), std::int64_t(dim));
  auto train_view = raft::make_device_matrix_view<const T, std::int64_t>(
    d_train.data(), std::int64_t(nt), std::int64_t(dim));
  auto output_view =
    raft::make_device_vector_view<T, std::int64_t>(d_output.data(), std::int64_t(nq));

  std::optional<raft::device_vector_view<const T, std::int64_t>> weights_opt;

  cuvs::distance::kde<T>(handle,
                         query_view,
                         train_view,
                         weights_opt,
                         output_view,
                         T(1.0),
                         T(nt),
                         DensityKernelType::Gaussian,
                         DistanceType::L2SqrtUnexpanded,
                         T(2.0));

  ASSERT_TRUE(cuvs::devArrMatchHost(
    h_expected.data(), d_output.data(), nq, cuvs::CompareApprox<T>(tolerance), stream));
}

